import{_ as e,c as a,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Superpowers 代理参考：code-reviewer 触发条件与六个审查维度完整使用指南 | 教程","description":"学习 Superpowers 代理系统的完整参考。本文详细介绍 code-reviewer 代理的触发条件、六个审查维度（计划对齐分析、代码质量评估、架构设计评审、文档和标准检查、问题识别建议、沟通协议）和最佳实践。掌握如何高效使用代码审查代理提升项目质量和开发效率，确保代码符合设计规范和最佳实践。","frontmatter":{"title":"Superpowers 代理参考：code-reviewer 触发条件与六个审查维度完整使用指南 | 教程","sidebarTitle":"代理参考","subtitle":"代理参考","description":"学习 Superpowers 代理系统的完整参考。本文详细介绍 code-reviewer 代理的触发条件、六个审查维度（计划对齐分析、代码质量评估、架构设计评审、文档和标准检查、问题识别建议、沟通协议）和最佳实践。掌握如何高效使用代码审查代理提升项目质量和开发效率，确保代码符合设计规范和最佳实践。","tags":["参考","代理","代码审查"],"prerequisite":["start-using-skills"],"order":280},"headers":[],"relativePath":"zh/obra/superpowers/appendix/agents-reference/index.md","filePath":"zh/obra/superpowers/appendix/agents-reference/index.md"}'),r={name:"zh/obra/superpowers/appendix/agents-reference/index.md"};function n(l,t,d,o,h,p){return i(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="代理参考" tabindex="-1">代理参考 <a class="header-anchor" href="#代理参考" aria-label="Permalink to &quot;代理参考&quot;">​</a></h1><p>Superpowers 通过代理系统为特定任务提供专业化的 AI 能力。每个代理都有明确的触发条件、审查标准和工作流程。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>代理与技能的区别：</p><table tabindex="0"><thead><tr><th>特性</th><th>技能 (Skills)</th><th>代理 (Agents)</th></tr></thead><tbody><tr><td>定义方式</td><td>Markdown 文件（SKILL.md）</td><td>Agent 定义文件（.md）</td></tr><tr><td>调用方式</td><td>通过 Skill tool 加载</td><td>通过 @mention 或 skill 调用</td></tr><tr><td>适用场景</td><td>通用工作流程和最佳实践</td><td>特定任务的专业化执行</td></tr><tr><td>数量</td><td>14 个</td><td>1 个（code-reviewer）</td></tr></tbody></table><h2 id="code-reviewer-代理" tabindex="-1">code-reviewer 代理 <a class="header-anchor" href="#code-reviewer-代理" aria-label="Permalink to &quot;code-reviewer 代理&quot;">​</a></h2><h3 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>code-reviewer</td></tr><tr><td><strong>类型</strong></td><td>Senior Code Reviewer</td></tr><tr><td><strong>领域</strong></td><td>代码审查、架构评审、质量保证</td></tr><tr><td><strong>模型</strong></td><td>inherit（继承当前会话的模型）</td></tr><tr><td><strong>定义文件</strong></td><td><code>agents/code-reviewer.md</code></td></tr></tbody></table><h3 id="触发条件" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件" aria-label="Permalink to &quot;触发条件&quot;">​</a></h3><p>当满足以下任一条件时，应调用 code-reviewer 代理：</p><ol><li><strong>完成主要项目步骤</strong>：逻辑代码块编写完成，需要验证是否符合原计划</li><li><strong>完成功能实现</strong>：重要功能实现完毕，需要对照架构文档或规划文档进行审查</li><li><strong>完成计划步骤</strong>：规划文档中的某个编号步骤已完成</li></ol><div class="info custom-block"><p class="custom-block-title">示例场景</p><p><strong>场景 1</strong>：用户完成了一个主要系统模块</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>&quot;I&#39;ve finished implementing the user authentication system as outlined in step 3 of our plan&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI 回应：</span></span>
<span class="line"><span>&quot;Great work! Now let me use the code-reviewer agent to review the implementation against our plan and coding standards&quot;</span></span></code></pre></div><p><strong>场景 2</strong>：用户完成了一个功能模块</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>&quot;The API endpoints for the task management system are now complete - that covers step 2 from our architecture document&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI 回应：</span></span>
<span class="line"><span>&quot;Excellent! Let me have the code-reviewer agent examine this implementation to ensure it aligns with our plan and follows best practices&quot;</span></span></code></pre></div></div><h3 id="审查维度" tabindex="-1">审查维度 <a class="header-anchor" href="#审查维度" aria-label="Permalink to &quot;审查维度&quot;">​</a></h3><p>code-reviewer 代理会从以下六个维度进行审查：</p><h4 id="_1-计划对齐分析" tabindex="-1">1. 计划对齐分析 <a class="header-anchor" href="#_1-计划对齐分析" aria-label="Permalink to &quot;1. 计划对齐分析&quot;">​</a></h4><ul><li>✅ 将实现与原始规划文档或步骤描述进行对比</li><li>✅ 识别偏离计划的实现方式、架构或需求</li><li>✅ 评估偏离是否是合理的改进或有害的偏离</li><li>✅ 验证所有计划功能已实现</li></ul><h4 id="_2-代码质量评估" tabindex="-1">2. 代码质量评估 <a class="header-anchor" href="#_2-代码质量评估" aria-label="Permalink to &quot;2. 代码质量评估&quot;">​</a></h4><ul><li>✅ 审查代码是否遵循既定的模式和约定</li><li>✅ 检查错误处理、类型安全和防御性编程</li><li>✅ 评估代码组织、命名约定和可维护性</li><li>✅ 评估测试覆盖率和测试实现质量</li><li>✅ 查找潜在的安全漏洞或性能问题</li></ul><h4 id="_3-架构和设计评审" tabindex="-1">3. 架构和设计评审 <a class="header-anchor" href="#_3-架构和设计评审" aria-label="Permalink to &quot;3. 架构和设计评审&quot;">​</a></h4><ul><li>✅ 确保实现遵循 SOLID 原则和既定架构模式</li><li>✅ 检查职责分离和松耦合</li><li>✅ 验证代码与现有系统的集成</li><li>✅ 评估可扩展性和可扩展性考虑</li></ul><h4 id="_4-文档和标准" tabindex="-1">4. 文档和标准 <a class="header-anchor" href="#_4-文档和标准" aria-label="Permalink to &quot;4. 文档和标准&quot;">​</a></h4><ul><li>✅ 验证代码包含适当的注释和文档</li><li>✅ 检查文件头、函数文档和内联注释是否存在且准确</li><li>✅ 确保遵循项目特定的编码标准和约定</li></ul><h4 id="_5-问题识别和建议" tabindex="-1">5. 问题识别和建议 <a class="header-anchor" href="#_5-问题识别和建议" aria-label="Permalink to &quot;5. 问题识别和建议&quot;">​</a></h4><ul><li>✅ 将问题清晰分类为：Critical（必须修复）、Important（应该修复）或 Suggestions（建议改进）</li><li>✅ 对每个问题提供具体示例和可操作的建议</li><li>✅ 识别计划偏离时，说明是有害的还是有益的</li><li>✅ 提出具体改进建议，并在有帮助时提供代码示例</li></ul><h4 id="_6-沟通协议" tabindex="-1">6. 沟通协议 <a class="header-anchor" href="#_6-沟通协议" aria-label="Permalink to &quot;6. 沟通协议&quot;">​</a></h4><ul><li>✅ 如果发现与计划的重大偏离，要求编码代理审查并确认更改</li><li>✅ 如果发现原始计划本身的问题，建议更新计划</li><li>✅ 对于实现问题，提供明确的修复指导</li><li>✅ 在突出显示问题之前，始终先承认做得好的地方</li></ul><h3 id="输出格式要求" tabindex="-1">输出格式要求 <a class="header-anchor" href="#输出格式要求" aria-label="Permalink to &quot;输出格式要求&quot;">​</a></h3><p>code-reviewer 代理的输出应：</p><ol><li><strong>结构化</strong>：按问题分类清晰组织</li><li><strong>可操作</strong>：每个问题都有具体建议和示例</li><li><strong>建设性</strong>：既指出问题也肯定优点</li><li><strong>简洁</strong>：全面但不冗长</li><li><strong>有帮助</strong>：帮助改进当前实现和未来开发实践</li></ol><h3 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">使用建议</p><ol><li><strong>及时调用</strong>：在完成主要步骤后立即调用，避免问题累积</li><li><strong>具体反馈</strong>：避免模糊的评价，提供代码行号和示例</li><li><strong>平衡反馈</strong>：既要指出问题，也要肯定优点</li><li><strong>可操作建议</strong>：每个建议都应该能直接转化为行动</li><li><strong>尊重计划</strong>：偏离计划时解释原因和影响</li></ol></div><h2 id="未来扩展" tabindex="-1">未来扩展 <a class="header-anchor" href="#未来扩展" aria-label="Permalink to &quot;未来扩展&quot;">​</a></h2><p>当前 Superpowers 仅包含 code-reviewer 代理，未来可能增加的代理类型：</p><table tabindex="0"><thead><tr><th>代理类型</th><th>潜在用途</th></tr></thead><tbody><tr><td>test-writer</td><td>专门生成测试用例的代理</td></tr><tr><td>debugger</td><td>专注于系统化调试的代理</td></tr><tr><td>security-auditor</td><td>安全审计专用代理</td></tr><tr><td>performance-optimizer</td><td>性能优化专项代理</td></tr><tr><td>documentation-writer</td><td>文档生成和维护的代理</td></tr></tbody></table><h2 id="相关技能" tabindex="-1">相关技能 <a class="header-anchor" href="#相关技能" aria-label="Permalink to &quot;相关技能&quot;">​</a></h2><p>代理系统与以下技能协同工作：</p><table tabindex="0"><thead><tr><th>技能名称</th><th>与代理的关系</th></tr></thead><tbody><tr><td>requesting-code-review</td><td>调用 code-reviewer 代理</td></tr><tr><td>receiving-code-review</td><td>接收代理审查反馈</td></tr><tr><td>subagent-driven-development</td><td>在子代理开发中使用代理</td></tr></tbody></table><h2 id="附录-代理定义文件结构" tabindex="-1">附录：代理定义文件结构 <a class="header-anchor" href="#附录-代理定义文件结构" aria-label="Permalink to &quot;附录：代理定义文件结构&quot;">​</a></h2><p>代理定义文件使用 YAML frontmatter 配置基本属性：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;代理名称&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  代理的详细描述，包括触发条件和使用示例</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">model</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">inherit | &lt;模型名称&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">代理的详细角色定义和工作流程</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>字段说明</strong>：</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必填</th><th>说明</th></tr></thead><tbody><tr><td>name</td><td>string</td><td>Y</td><td>代理唯一标识符（kebab-case）</td></tr><tr><td>description</td><td>string</td><td>Y</td><td>代理的用途和触发条件描述</td></tr><tr><td>model</td><td>string</td><td>N</td><td>使用的模型，inherit 表示继承当前会话模型</td></tr></tbody></table><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>code-reviewer 代理定义</td><td><a href="https://github.com/obra/superpowers/blob/main/agents/code-reviewer.md" target="_blank" rel="noreferrer"><code>agents/code-reviewer.md</code></a></td><td>1-49</td></tr></tbody></table><p><strong>关键配置</strong>：</p><ul><li><code>name: code-reviewer</code>：代理唯一标识符</li><li><code>model: inherit</code>：继承当前会话模型</li><li><code>description</code>：包含触发条件和使用示例</li></ul><p><strong>审查维度</strong>：</p><ul><li>Plan Alignment Analysis（计划对齐分析）</li><li>Code Quality Assessment（代码质量评估）</li><li>Architecture and Design Review（架构和设计评审）</li><li>Documentation and Standards（文档和标准）</li><li>Issue Identification and Recommendations（问题识别和建议）</li><li>Communication Protocol（沟通协议）</li></ul></details>`,45)])])}const g=e(r,[["render",n]]);export{u as __pageData,g as default};
